import React, { useState } from 'react';

import ResumeService from '../services/ResumeService';

function ResumeForm() {

  const [resume, setResume] = useState({

    fullName: '',
    email: '',
    phone: '',

    github: '',
    linkedin: '',
    portfolio: '',

    profileImage: '',

    summary: '',

    skills: [''],
    education: [''],
    experience: [''],
    projects: [''],
    languages: [''],
    hobbies: ['']

  });

  // ================= INPUT CHANGE =================

  const handleChange = (e) => {

    setResume({

      ...resume,

      [e.target.name]: e.target.value

    });
  };

  // ================= IMAGE UPLOAD =================

  const handleImageUpload = (e) => {

    const file = e.target.files[0];

    if (!file) return;

    if (file.size > 2 * 1024 * 1024) {

      alert(
        'Image size should be less than 2MB'
      );

      return;
    }

    const reader = new FileReader();

    reader.onloadend = () => {

      setResume(prev => ({

        ...prev,

        profileImage: reader.result

      }));
    };

    reader.readAsDataURL(file);
  };

  // ================= ARRAY CHANGE =================

  const handleArrayChange = (
    index,
    field,
    value
  ) => {

    const updated =
      [...resume[field]];

    updated[index] = value;

    setResume({

      ...resume,

      [field]: updated

    });
  };

  // ================= ADD FIELD =================

  const addField = (field) => {

    setResume({

      ...resume,

      [field]: [

        ...resume[field],
        ''

      ]

    });
  };

  // ================= REMOVE FIELD =================

  const removeField = (
    field,
    index
  ) => {

    const updated =
      [...resume[field]];

    updated.splice(index, 1);

    setResume({

      ...resume,

      [field]:
        updated.length > 0
          ? updated
          : ['']

    });
  };

  // ================= AI SUMMARY =================

  const generateAISummary = async () => {

    try {

      const skillsText =
        resume.skills
          .filter(skill =>
            skill.trim() !== ''
          )
          .join(', ');

      if (!skillsText) {

        alert(
          'Please Enter Skills First'
        );

        return;
      }

      const response =
        await ResumeService.generateSummary(
          skillsText
        );

      setResume(prev => ({

        ...prev,

        summary: response.data

      }));

    } catch (error) {

      console.log(error);

      if (error.response) {

        alert(
          'AI Error : ' +
          error.response.status
        );

      } else {

        alert(
          'Backend Server Not Running'
        );
      }
    }
  };

  // ================= SUBMIT =================

  const handleSubmit = async (e) => {

    e.preventDefault();

    try {

      const token =
        localStorage.getItem('token');

      if (!token) {

        alert(
          'Please Login First'
        );

        return;
      }

      const formattedResume = {

        fullName:
          resume.fullName,

        email:
          resume.email,

        phone:
          resume.phone,

        github:
          resume.github,

        linkedin:
          resume.linkedin,

        portfolio:
          resume.portfolio,

        profileImage:
          resume.profileImage,

        summary:
          resume.summary,

        skills:
          resume.skills
            .filter(item =>
              item.trim() !== ''
            )
            .join(', '),

        education:
          resume.education
            .filter(item =>
              item.trim() !== ''
            )
            .join('\n'),

        experience:
          resume.experience
            .filter(item =>
              item.trim() !== ''
            )
            .join('\n'),

        projects:
          resume.projects
            .filter(item =>
              item.trim() !== ''
            )
            .join('\n'),

        languages:
          resume.languages
            .filter(item =>
              item.trim() !== ''
            )
            .join(', '),

        hobbies:
          resume.hobbies
            .filter(item =>
              item.trim() !== ''
            )
            .join(', ')
      };

      console.log(
        'Sending Resume:',
        formattedResume
      );

      const response =
        await ResumeService.saveResume(
          formattedResume
        );

      console.log(response.data);

      alert(
        'Resume Saved Successfully'
      );

      // STAY ON SAME PAGE

      window.scrollTo({

        top: 0,

        behavior: 'smooth'

      });

      // RESET FORM

      setResume({

        fullName: '',
        email: '',
        phone: '',

        github: '',
        linkedin: '',
        portfolio: '',

        profileImage: '',

        summary: '',

        skills: [''],
        education: [''],
        experience: [''],
        projects: [''],
        languages: [''],
        hobbies: ['']

      });

    } catch (error) {

      console.log(error);

      if (error.response) {

        alert(

          'Error : ' +

          error.response.status +

          ' - ' +

          JSON.stringify(
            error.response.data
          )
        );

      } else if (error.request) {

        alert(
          'No Response From Backend Server'
        );

      } else {

        alert(
          'Error Saving Resume'
        );
      }
    }
  };

  // ================= COMMON ARRAY UI =================

  const renderArrayField = (
    title,
    field,
    type = 'input'
  ) => (

    <div className="mb-4">

      <h4>{title}</h4>

      {

        resume[field].map((item, index) => (

          <div
            className="d-flex mb-2"
            key={index}
          >

            {

              type === 'textarea'

                ? (

                  <textarea
                    value={item}
                    className="form-control me-2"
                    rows="3"
                    onChange={(e) =>
                      handleArrayChange(
                        index,
                        field,
                        e.target.value
                      )
                    }
                  />

                )

                : (

                  <input
                    type="text"
                    value={item}
                    className="form-control me-2"
                    onChange={(e) =>
                      handleArrayChange(
                        index,
                        field,
                        e.target.value
                      )
                    }
                  />

                )
            }

            <button
              type="button"
              className="btn btn-danger"
              onClick={() =>
                removeField(
                  field,
                  index
                )
              }
            >

              Remove

            </button>

          </div>

        ))
      }

      <button
        type="button"
        className="btn btn-primary"
        onClick={() =>
          addField(field)
        }
      >

        Add {title}

      </button>

    </div>
  );

  // ================= UI =================

  return (

    <div className="container mt-5 mb-5">

      <div className="card shadow p-5">

        <h1 className="text-center mb-5">

          Create Resume

        </h1>

        <form onSubmit={handleSubmit}>

          {/* BASIC DETAILS */}

          <input
            type="text"
            name="fullName"
            value={resume.fullName}
            placeholder="Full Name"
            className="form-control mb-3"
            onChange={handleChange}
            required
          />

          <input
            type="email"
            name="email"
            value={resume.email}
            placeholder="Email"
            className="form-control mb-3"
            onChange={handleChange}
            required
          />

          <input
            type="text"
            name="phone"
            value={resume.phone}
            placeholder="Phone"
            className="form-control mb-3"
            onChange={handleChange}
            required
          />

          {/* LINKS */}

          <input
            type="text"
            name="github"
            value={resume.github}
            placeholder="GitHub URL"
            className="form-control mb-3"
            onChange={handleChange}
          />

          <input
            type="text"
            name="linkedin"
            value={resume.linkedin}
            placeholder="LinkedIn URL"
            className="form-control mb-3"
            onChange={handleChange}
          />

          <input
            type="text"
            name="portfolio"
            value={resume.portfolio}
            placeholder="Portfolio URL"
            className="form-control mb-4"
            onChange={handleChange}
          />

          {/* IMAGE */}

          <div className="mb-4">

            <label className="form-label">

              Upload Profile Image

            </label>

            <input
              type="file"
              accept="image/*"
              className="form-control"
              onChange={handleImageUpload}
            />

          </div>

          {

            resume.profileImage && (

              <div className="mb-4">

                <img
                  src={resume.profileImage}
                  alt="Profile"
                  style={{

                    width: '150px',

                    height: '150px',

                    borderRadius: '50%',

                    objectFit: 'cover',

                    border:
                      '3px solid #0d6efd'

                  }}
                />

              </div>
            )
          }

          {/* AI BUTTON */}

          <button
            type="button"
            className="btn btn-dark mb-4"
            onClick={generateAISummary}
          >

            Generate AI Summary

          </button>

          {/* SUMMARY */}

          <textarea
            name="summary"
            value={resume.summary}
            placeholder="Professional Summary"
            className="form-control mb-4"
            rows="4"
            onChange={handleChange}
          />

          {/* DYNAMIC FIELDS */}

          {renderArrayField(
            'Skills',
            'skills'
          )}

          {renderArrayField(
            'Education',
            'education',
            'textarea'
          )}

          {renderArrayField(
            'Experience',
            'experience',
            'textarea'
          )}

          {renderArrayField(
            'Projects',
            'projects',
            'textarea'
          )}

          {renderArrayField(
            'Languages',
            'languages'
          )}

          {renderArrayField(
            'Hobbies',
            'hobbies'
          )}

          {/* SAVE BUTTON */}

          <button
            type="submit"
            className="btn btn-success w-100"
          >

            Save Resume

          </button>

        </form>

      </div>

    </div>
  );
}

export default ResumeForm;
